spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 11000;
    var progress = (t % duration) / duration;

    var rows = 4;
    var cols = 3;
    var cellW = 35;
    var cellH = 20;
    var gridW = cols * cellW;
    var gridH = rows * cellH;
    var startX = (W - gridW) / 2;
    var startY = (H - gridH) / 2 - 15;

    // Progress stages
    // 0 - 2s: stage 1 (8/12 cell view)
    // 2s - 5s: stage 2 (draw columns highlighting)
    // 5s - 8s: stage 3 (merge cells into solid columns)
    // 8s - 11s: stage 4 (final text showing 2/3)

    var stage = 1;
    if (progress >= 0.18 && progress < 0.45) stage = 2;
    else if (progress >= 0.45 && progress < 0.72) stage = 3;
    else if (progress >= 0.72) stage = 4;

    // Draw grid
    for (var c = 0; c < cols; c++) {
      for (var r = 0; r < rows; r++) {
        var cx = startX + c * cellW;
        var cy = startY + r * cellH;

        // Column 0 and 1 are shaded (total 8 cells)
        var isShaded = (c < 2);

        ctx.beginPath();
        ctx.rect(cx, cy, cellW, cellH);

        if (stage >= 3) {
          // In stage 3/4, draw columns merged
          if (isShaded) {
            ctx.fillStyle = '#10B981'; // Green for simplified
          } else {
            ctx.fillStyle = '#1F2937';
          }
        } else {
          if (isShaded) {
            ctx.fillStyle = '#3B82F6'; // Blue for initial
          } else {
            ctx.fillStyle = '#1F2937';
          }
        }
        ctx.fill();

        // Border
        if (stage < 3) {
          ctx.strokeStyle = '#374151';
          ctx.lineWidth = 1;
          ctx.stroke();
        }
      }
    }

    // Draw column outlines for stage 2 and 3
    if (stage === 2) {
      for (var c = 0; c < cols; c++) {
        ctx.beginPath();
        ctx.rect(startX + c * cellW, startY, cellW, gridH);
        ctx.strokeStyle = '#F59E0B'; // Yellow divider
        ctx.lineWidth = 2.5;
        ctx.stroke();
      }
    } else if (stage >= 3) {
      // Thick outer columns
      for (var c = 0; c < cols; c++) {
        ctx.beginPath();
        ctx.rect(startX + c * cellW, startY, cellW, gridH);
        ctx.strokeStyle = '#4B5563';
        ctx.lineWidth = 2;
        ctx.stroke();
      }
    }

    // Texts
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('8 / 12 Shaded', W / 2, H - 35);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.fillText('8 cells out of 12 equal divisions', W / 2, H - 15);
    } else if (stage === 2) {
      ctx.fillStyle = '#F59E0B';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Grouping by Columns', W / 2, H - 35);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.fillText('We can group the 12 cells into 3 columns of 4', W / 2, H - 15);
    } else if (stage === 3) {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('2 / 3 Columns Shaded', W / 2, H - 35);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.fillText('Merging cells: the shaded area is still identical!', W / 2, H - 15);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Simplest Form: 2 / 3', W / 2, H - 35);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = 'bold 12px -apple-system, sans-serif';
      ctx.fillText('Divided numerator & denominator by GCD (4)', W / 2, H - 15);
    }
  }
};
